// WHY NOT THE AI AGENT NODE?
// Measured on this machine: the LangChain Agent node took ~14s per reply, while the
// SAME model with the SAME prompt answers in ~2s when called directly. The agent runs
// a ReAct loop (several LLM round-trips, a scratchpad, tool-choice reasoning) — none of
// which this lab needs. For a conversation you must not keep waiting for, that overhead
// is the whole difference between "interactive" and "awkward".
//
// So we build the chat payload ourselves and call Ollama once.
//
// History comes from the BROWSER (it already has the transcript), which also keeps this
// flow stateless — no memory node, no session store.

const body = $input.first().json.body || {};
const message = (body.message || '').toString().trim();
const history = Array.isArray(body.history) ? body.history.slice(-6) : [];

const SYSTEM = `You are Aria, a friendly AI receptionist for Tertiary Infotech Academy.

You are SPOKEN ALOUD by a talking avatar, so:
- Reply in ONE short sentence. Two at the very most.
- Plain spoken English. No markdown, no bullets, no emoji, no URLs.
- Say numbers in words: "two days", "nine thirty in the morning".
- If you do not know, say so briefly and offer a colleague follow-up. Never invent a price, a date or a policy.

WHAT YOU KNOW
- The academy runs WSQ short courses in AI, automation and data.
- Classes run 9:30am to 6:30pm on weekdays at our training centre.
- Course fees vary; funding is available for eligible Singaporeans.
- To enrol, a learner registers on the website.`;

const messages = [
  { role: 'system', content: SYSTEM },
  ...history.map((h) => ({ role: h.role === 'you' ? 'user' : 'assistant', content: h.text })),
  { role: 'user', content: message || 'Hello' },
];

return [{ json: {
  ollama: {
    model: 'gemma4:latest',
    stream: false,
    // gemma4 is a THINKING model: left alone it spends its whole token budget on an
    // internal monologue and returns message.content EMPTY (done_reason: 'length').
    // The avatar then says "Sorry, I did not catch that" while the model is busy
    // reasoning beautifully in private. Turn thinking off — this is a receptionist,
    // not a maths olympiad.
    think: false,
    keep_alive: '30m',          // keep the 9.6 GB model resident — a cold load costs seconds
    messages,
    options: {
      num_predict: 120,         // enough for two spoken sentences, not enough to ramble
      temperature: 0.6,
    },
  },
  warm: !!body.warm,
} }];

// The avatar SPEAKS this, so strip anything that does not read aloud: a stray asterisk
// becomes an audible "asterisk" in the browser's voice.
const res = $input.first().json;
// If a thinking model ever slips through with an empty content field, we would
// rather say something true from its reasoning than 'I did not catch that'.
let reply = (res.message?.content || '').toString();
const starved = !reply && res.done_reason === 'length';

reply = reply
  .replace(/[*_`#>]/g, '')
  .replace(/^\s*[-•]\s*/gm, '')
  .replace(/https?:\/\/\S+/g, 'the link on our website')
  .replace(/\s+/g, ' ')
  .trim();

if (!reply) {
  reply = res.error
    ? 'My brain is not answering. Check that Ollama is running.'
    : starved
      ? 'Sorry, I ran out of words. Ask me that again?'
      : 'Sorry, I did not catch that. Could you say it again?';
}

// Report where the time went, so the lab can SHOW the latency rather than claim it.
const ms = (n) => Math.round((n || 0) / 1e6);

return [{ json: {
  reply,
  timing: {
    total_ms: ms(res.total_duration),
    model_load_ms: ms(res.load_duration),
    prompt_ms: ms(res.prompt_eval_duration),
    generate_ms: ms(res.eval_duration),
    tokens: res.eval_count || 0,
  },
} }];
